package mhir.main.aetherling

import mhir.gen.verilog.{
  VerilogProjectInitializer,
  VerilogTestRunner,
  VerilogTestbenchGenerator
}
import mhir.gen.vhdl.{VhdlTestRunner, VhdlTestbenchGenerator}
import mhir.gen.{TestInput, TestPassed}
import mhir.ir._
import mhir.testing.HardwareTestObj
import org.scalatest.funsuite.AnyFunSuite

import scala.annotation.tailrec

/** Tests that the VHDL designs produced by [[mhir.main.aetherling.Compiler]]
  * behave the same as the Verilog designs generated by
  * [[https://dl.acm.org/doi/10.1145/3385412.3385983 Aetherling]].
  */
class AetherlingBenchmarkTests extends AnyFunSuite {
  private val AetherlingBenchmarksDir =
    os.pwd / "src" / "test" / "resources" / "aetherling_benchmarks" / "original"
  private val VerilogBenchmarksDir =
    os.pwd / "src" / "test" / "resources" / "aetherling_benchmarks" / "verilog"
  private val SimplifiedAetherlingBenchmarksDir =
    os.pwd / "src" / "test" / "resources" / "aetherling_benchmarks" / "simplified"
  private val VhdlDir = os.pwd / "src" / "test" / "vhdl"
  private val VerilogDir = os.pwd / "src" / "test" / "verilog"

  /** Whether to save the parsed programs to
    * [[SimplifiedAetherlingBenchmarksDir]].
    *
    * If false, then the programs in [[SimplifiedAetherlingBenchmarksDir]] will
    * be used as the expected outputs and nothing will be written.
    *
    * If true, then the compiler outputs will be saved to
    * [[SimplifiedAetherlingBenchmarksDir]]. This is useful in case you want to
    * change the expected outputs, just don't forget to review the outputs and
    * change this field back to `false`.
    */
  private val SaveChanges: Boolean = false

  test("SaveChanges") {
    assert(!SaveChanges)
  }

  for (f <- os.list(AetherlingBenchmarksDir)) {
    val benchName = f.baseName

    test(s"$benchName:changes-to-simplified-version") {
      mhir.ir.reset()
      val inFile = AetherlingBenchmarksDir / s"$benchName.txt"
      val outDir = VhdlDir / "aetherling" / s"${benchName}_test"
      val args = Args(inFile = inFile, outDir = outDir, emitHdl = false)
      val f = Compiler.compile(args)
      val actual = ExprPrinter.display(f)
      val expectedPath = SimplifiedAetherlingBenchmarksDir / s"$benchName.txt"
      if (SaveChanges) {
        os.write.over(expectedPath, actual)
      } else {
        val expected = os.read(expectedPath)
        if (actual != expected) {
          fail(
            "the final program generated by the compiler seems to have changed,"
              + " which may invalidate previous measurements (e.g., resource usage, fmax)"
          )
        }
      }
      assume(!SaveChanges)
    }

    test(s"$benchName:vhdl:simplified", HardwareTestObj) {
      val (inputs, outputs) = AetherlingBenchmarkTests.ioByBenchmark(benchName)
      val inFile = AetherlingBenchmarksDir / s"$benchName.txt"
      val outDir = VhdlDir / "aetherling" / s"${benchName}_test"
      if (os.exists(outDir)) os.remove.all(outDir)
      val args = Args(inFile = inFile, outDir = outDir)
      val f = Compiler.compile(args)
      VhdlTestbenchGenerator.makeTestbench(
        inputsByVar = getVhdlInputs(f, inputs),
        out = outputs,
        dir = outDir,
        testNotReady = false
      )
      assert(VhdlTestRunner.testExistingProject(outDir) == TestPassed)
    }

    test(s"$benchName:vhdl:unsimplified", HardwareTestObj) {
      val (inputs, outputs) = AetherlingBenchmarkTests.ioByBenchmark(benchName)
      val inFile = AetherlingBenchmarksDir / s"$benchName.txt"
      val outDir = VhdlDir / "aetherling" / s"${benchName}_test_unsimplified"
      if (os.exists(outDir)) os.remove.all(outDir)
      val args = Args(inFile = inFile, outDir = outDir, optimize = false)
      val f = Compiler.compile(args)
      VhdlTestbenchGenerator.makeTestbench(
        inputsByVar = getVhdlInputs(f, inputs),
        out = outputs,
        dir = outDir,
        testNotReady = false
      )
      assert(VhdlTestRunner.testExistingProject(outDir) == TestPassed)
    }

    test(s"$benchName:verilog", HardwareTestObj) {
      val (inputs, outputs) = AetherlingBenchmarkTests.ioByBenchmark(benchName)
      val projectDir = VerilogDir / s"aetherling" / s"${benchName}_test"
      VerilogProjectInitializer.initProj(
        projectDir,
        VerilogBenchmarksDir / s"$benchName.v",
        overwrite = true
      )
      VerilogTestbenchGenerator.makeTestbench(inputs, outputs, projectDir)
      assert(VerilogTestRunner.testExistingProject(projectDir) == TestPassed)
    }
  }

  @tailrec
  private def getVhdlInputs(
      f: Expr,
      inputs: Seq[TestInput],
      inputByVar: Map[Param, TestInput] = Map()
  ): Map[Param, TestInput] = {
    if (inputs.isEmpty) {
      inputByVar
    } else {
      f.asInstanceOf[Function] match {
        case Function(x, body) =>
          getVhdlInputs(body, inputs.tail, inputByVar + (x -> inputs.head))
      }
    }
  }
}

object AetherlingBenchmarkTests {

  private val mapIO: Map[String, (Seq[TestInput], StmLiteral)] =
    Seq(1, 2, 4, 5, 8, 10, 20, 40, 200)
      .map(par => {
        val flatInputs = (0 until 200).map(i => C(i)(U8))
        val flatOutputs = (0 until 200).map(i => C(i + 5)(U8))
        val (inputs, outputs) = par match {
          case 1 =>
            (
              TestInput(flatInputs.map(e => Some(e))),
              StmLiteral(flatOutputs: _*)()
            )
          case _ =>
            (
              TestInput(
                flatInputs
                  .grouped(par)
                  .map(xs => Some(VecLiteral(xs: _*)()))
                  .toSeq
              ),
              StmLiteral(
                flatOutputs
                  .grouped(par)
                  .map(xs => VecLiteral(xs: _*)())
                  .toSeq: _*
              )()
            )
        }
        s"map_$par" -> (Seq(inputs), outputs)
      })
      .toMap

  private val sumIO: Map[String, (Seq[TestInput], StmLiteral)] =
    Seq(1, 2, 3, 4, 5, 6, 7, 8)
      .map(par => {
        val flatInputs = (0 until 840).map(i => C(i)(U32))
        val sum = C((0 until 840).sum)(U32)
        val inputs = par match {
          case 1 =>
            TestInput(flatInputs.map(e => Some(e)))
          case _ =>
            TestInput(
              flatInputs
                .grouped(par)
                .map(xs => Some(VecLiteral(xs: _*)()))
                .toSeq
            )
        }
        s"sum_1_${840 / par}" -> (Seq(inputs), StmLiteral(sum)())
      })
      .toMap

  private val dotIO: Map[String, (Seq[TestInput], StmLiteral)] =
    Seq(1, 2, 3, 4, 5, 6, 7, 8)
      .map(par => {
        val flatInputs1 = (0 until 840).map(_ % 16)
        val flatInputs2 = (839 to 0 by -1).map(_ % 16)
        val result =
          flatInputs1.zip(flatInputs2).map({ case (x, y) => x * y }).sum
        val (inputs1, inputs2) = par match {
          case 1 =>
            (
              TestInput(flatInputs1.map(e => Some(C(e)(U16)))),
              TestInput(flatInputs2.map(e => Some(C(e)(U16))))
            )
          case _ =>
            (
              TestInput(
                flatInputs1
                  .grouped(par)
                  .map(xs => Some(VecLiteral(xs.map(C(_)(U16)): _*)()))
                  .toSeq
              ),
              TestInput(
                flatInputs2
                  .grouped(par)
                  .map(xs => Some(VecLiteral(xs.map(C(_)(U16)): _*)()))
                  .toSeq
              )
            )
        }
        s"dot_1_${840 / par}" -> (
          Seq(inputs1, inputs2),
          StmLiteral(
            C(result)(U16)
          )()
        )
      })
      .toMap

  /** Maps benchmark names (e.g., "map_1") to inputs and expected outputs.
    *
    * @note
    *   this must be manually updated whenever a new benchmark is added.
    */
  private val ioByBenchmark: Map[String, (Seq[TestInput], StmLiteral)] = (
    mapIO
      ++ sumIO
      ++ dotIO
  )
}
